mapper.select:
/** 피드백 리스트 */
SELECT a.*
,(SELECT COUNT(*) FROM t_feedback_question WHERE FB_IDX=a.IDX AND QT_TYPE=0) QT_TYPE0_CNT
,(SELECT COUNT(*) FROM t_feedback_question WHERE FB_IDX=a.IDX AND QT_TYPE in (1,2,3)) QT_TYPE1_CNT
FROM t_feedback a
WHERE 1=1

AND ORG_CD=#{orgCd} 


AND reg_id=#{regId}  


AND title like concat('%',#{srchWrd},'%')

ORDER BY REG_TIME DESC

SELECT a.FB_IDX,a.QT_IDX,a.CHOICE ,COUNT(*) AS_CNT FROM t_feedback_answer a WHERE a.FB_IDX=#{fbIdx} AND QT_IDX=#{qtIdx} AND CHOICE=#{chIdx}
and a.edu_seq in
#{item}
GROUP by a.FB_IDX,a.QT_IDX,a.CHOICE ORDER BY a.FB_IDX,a.QT_IDX,a.CHOICE

mapper.update:
UPDATE t_feedback
SET TITLE=#{title} ,MOD_TIME=#{modTime},MOD_ID=#{modId},CONTENT=#{content}
WHERE IDX=#{idx}

mapper.select:
/** 주관식 답변 조회 */
select * from t_feedback_answer 
where fb_idx=#{fbIdx} and qt_idx=#{qtIdx}
and ((choice=0 and answer is not null and replace(answer,' ','') != '') or (choice!=0))


	and edu_seq in 

		#{item}



order by reg_time

/** 만족도조사 게시판 리스트 */ SELECT a.* ,(select user_nm from t_user_info where user_id = a.reg_id) reg_nm ,(SELECT COUNT(*) FROM t_feedback_question WHERE FB_IDX=a.IDX AND QT_TYPE=0) QT_TYPE0_CNT ,(SELECT COUNT(*) FROM t_feedback_question WHERE FB_IDX=a.IDX AND QT_TYPE in (1,2,3)) QT_TYPE1_CNT FROM t_feedback a where 1=1
ORDER BY REG_TIME DESC
LIMIT #{firstIndex},#{rowCnt}
